const firstLineParts = lines[0].split(/\s+/).map(Number);
const C = firstLineParts[0];
const N = firstLineParts[1];

const cache = new LRUCache(C);
const getResults: number[] = [];

for (let i = 1; i <= N; i++) {
    const line = lines[i];
    if (!line) continue;
    const parts = line.split(/\s+/);
    const cmd = parts[0];
