        getResults.push(val === null ? -1 : val);
    } else if (cmd === 'DEL') {
        const key = parts[1];
        cache.del(key);
    }
}

if (getResults.length === 0) {
    console.log('EMPTY');
} else {
    console.log(getResults.join(' '));
}

const remainingKeys = cache.getAllKeys();
if (remainingKeys.length === 0) {
    console.log('EMPTY');
} else {
    console.log(remainingKeys.join(' '));
}
